// src/App.js
import React, { useState, useEffect } from "react";
import { BrowserRouter as Router, Routes, Route, useLocation, Navigate } from "react-router-dom";
import { AnimatePresence, motion } from "framer-motion";

// Context
import { AuthProvider, useAuth } from "./context/AuthContext";

// Components
import Navbar from "./components/Navbar";
import Footer from "./components/Footer";
import SearchBar from "./components/SearchBar";

// Pages
import Home from "./pages/Home";
import About from "./pages/About";
import Domains from "./pages/Domains";
import Purpose from "./pages/Purpose";
import Team from "./pages/Team";
import Vision from "./pages/Vision";
import Careers from "./pages/Careers";
import Contact from "./pages/Contact";
import NotFound from "./pages/NotFound";
import Login from "./pages/Login";
import Signup from "./pages/Signup";
import Dashboard from "./pages/Dashboard";
import Profile from "./pages/Profile";

// -------------------- Protected Route Wrapper --------------------
function ProtectedRoute({ children }) {
  const { user, initializing } = useAuth();

  if (initializing) return <div className="text-center text-white mt-20">Loading...</div>;

  return user ? children : <Navigate to="/login" replace />;
}

// -------------------- Animated Routes Wrapper --------------------
function AnimatedRoutes() {
  const location = useLocation();

  const pageVariants = {
    initial: { opacity: 0, y: 20 },
    animate: { opacity: 1, y: 0, transition: { duration: 0.4, ease: "easeOut" } },
    exit: { opacity: 0, y: -20, transition: { duration: 0.3, ease: "easeIn" } },
  };

  return (
    <AnimatePresence mode="wait">
      <Routes location={location} key={location.pathname}>
        {[
          { path: "/", element: <Home />, title: "Home - Godemar’s Empire" },
          { path: "/about", element: <About />, title: "About Us - Godemar’s Empire" },
          { path: "/domains", element: <Domains />, title: "Domains - Godemar’s Empire" },
          { path: "/purpose", element: <Purpose />, title: "Our Purpose - Godemar’s Empire" },
          { path: "/team", element: <Team />, title: "Meet the Team - Godemar’s Empire" },
          { path: "/vision", element: <Vision />, title: "Vision - Godemar’s Empire" },
          { path: "/careers", element: <Careers />, title: "Careers - Godemar’s Empire" },
          { path: "/contact", element: <Contact />, title: "Contact - Godemar’s Empire" },
          { path: "/login", element: <Login />, title: "Login - Godemar’s Empire" },
          { path: "/signup", element: <Signup />, title: "Sign Up - Godemar’s Empire" },
          {
            path: "/dashboard",
            element: (
              <ProtectedRoute>
                <Dashboard />
              </ProtectedRoute>
            ),
            title: "Dashboard - Godemar’s Empire",
          },
          {
            path: "/profile",
            element: (
              <ProtectedRoute>
                <Profile />
              </ProtectedRoute>
            ),
            title: "Profile - Godemar’s Empire",
          },
          { path: "*", element: <NotFound />, title: "Page Not Found - Godemar’s Empire" },
        ].map(({ path, element, title }) => (
          <Route
            key={path}
            path={path}
            element={
              <PageWrapper title={title} variants={pageVariants}>
                {element}
              </PageWrapper>
            }
          />
        ))}
      </Routes>
    </AnimatePresence>
  );
}

// -------------------- Page Wrapper --------------------
function PageWrapper({ children, title, variants }) {
  useEffect(() => {
    document.title = title;
  }, [title]);

  return (
    <motion.div
      className="min-h-screen"
      variants={variants}
      initial="initial"
      animate="animate"
      exit="exit"
    >
      {children}
    </motion.div>
  );
}

// -------------------- Main App Component --------------------
function App() {
  const [showSearch, setShowSearch] = useState(false);

  // Keyboard shortcut: "/" or "Ctrl+K" opens search
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === "/" && !showSearch) {
        e.preventDefault();
        setShowSearch(true);
      }
      if ((e.ctrlKey || e.metaKey) && e.key.toLowerCase() === "k") {
        e.preventDefault();
        setShowSearch(true);
      }
      if (e.key === "Escape") {
        setShowSearch(false);
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  }, [showSearch]);

  return (
    <AuthProvider>
      <Router>
        {/* Navbar fixed at top */}
        <Navbar onSearchClick={() => setShowSearch(true)} />

        {/* Global Search Overlay */}
        {showSearch && <SearchBar onClose={() => setShowSearch(false)} />}

        {/* Main content area */}
        <div className="pt-16 pb-40 bg-black dark:bg-gray-900">
          <AnimatedRoutes />
        </div>

        {/* Sticky Footer */}
        <Footer />
      </Router>
    </AuthProvider>
  );
}

export default App;
